# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using System;
using System.Collections.Concurrent;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int MaxSeats { get; set; }
    public int RemainingSeats { get; set; }

    public virtual ICollection<Purchase> Purchases { get; set; } = new HashSet<Purchase>();
}

public class Purchase
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int Quantity { get; set; }
    public DateTimeOffset CreatedAt { get; set; }

    public virtual Event Event { get; set; }
}

public class ApplicationDbContext : DbContext
{
    public ApplicationDbContext(DbContextOptions<ApplicationDbContext> options)
        : base(options) {}

    public DbSet<Event> Events { get; set; }
    public DbSet<Purchase> Purchases { get; set; }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>()
            .HasAlwaysSpecifiedConcurrencyToken();

        modelBuilder.Entity<Purchase>()
            .HasAlwaysSpecifiedConcurrencyToken();
    }
}

public async Task BuyTickets(int eventId, int quantity, CancellationToken cancellationToken)
{
    using var context = new ApplicationDbContext();
    var eventToUpdate = await context.Events
        .Include(e => e.Purchases)
        .FirstOrDefaultAsync(e => e.Id == eventId, cancellationToken);

    if (eventToUpdate == null || eventToUpdate.RemainingSeats < quantity)
        throw new InvalidOperationException("Invalid event or no seats available.");

    var remainingSeats = eventToUpdate.RemainingSeats - quantity;
    eventToUpdate.RemainingSeats = remainingSeats;
    await context.SaveChangesAsync(cancellationToken);

    for (int i = 0; i < quantity; i++)
    {
        var purchase = new Purchase
        {
            EventId = eventToUpdate.Id,
            Quantity = 1,
            CreatedAt = DateTimeOffset.UtcNow,
            ConcurrencyStamp = eventToUpdate.ConcurrencyStamp // This is the concurrency token
        };

        eventToUpdate.Purchases.Add(purchase);
    }

    await context.SaveChangesAsync(cancellationToken);
}